export default function EnterpriseDashboard() {
  return (
    <div className="p-8">
      <h1 className="mb-4 text-2xl font-bold text-gray-800">Enterprise Dashboard</h1>
      <p className="text-gray-600">
        Welcome to the Enterprise Dashboard. Select an option from the sidebar.
      </p>
    </div>
  );
}

import Link from 'next/link';

export const metadata = {
  title: 'Unauthorized',
  description: 'Access denied',
};

export default function Page() {
  return (
    <div className="mx-auto max-w-xl space-y-4 p-10">
      <h1 className="text-2xl font-black text-slate-900">Unauthorized</h1>
      <p className="text-slate-600">You do not have permission to access this page.</p>
      <Link
        href="/login"
        className="inline-flex rounded-full bg-red-600 px-5 py-2 text-sm font-semibold text-white hover:bg-red-700"
      >
        Back to login
      </Link>
    </div>
  );
}

'use client';

import { Input, Select } from 'antd';

import Modal from '@/components/ui/Modal';

export default function AdminUserCreateModal({
  open,
  onCancel,
  onOk,
  confirmLoading,
  createForm,
  setCreateForm,
  roleOptions,
  unitRequired,
}) {
  return (
    <Modal open={open} onCancel={onCancel}>
      <Modal.Header>
        <Modal.Title>Create admin user</Modal.Title>
      </Modal.Header>

      <Modal.Content>
        <Input
          placeholder="Full name"
          value={createForm.fullName}
          onChange={(e) => setCreateForm((p) => ({ ...p, fullName: e.target.value }))}
        />
        <Input
          placeholder="Email"
          value={createForm.email}
          onChange={(e) => setCreateForm((p) => ({ ...p, email: e.target.value }))}
        />
        <Select
          value={createForm.role}
          onChange={(v) => setCreateForm((p) => ({ ...p, role: v }))}
          options={roleOptions}
          className="w-full"
        />
        <Input
          placeholder="Phone number (optional)"
          value={createForm.phoneNumber}
          onChange={(e) => setCreateForm((p) => ({ ...p, phoneNumber: e.target.value }))}
        />
        <Input
          placeholder={
            unitRequired(createForm.role)
              ? 'UnitId (required for selected role)'
              : 'UnitId (optional)'
          }
          value={createForm.unitId}
          onChange={(e) => setCreateForm((p) => ({ ...p, unitId: e.target.value }))}
        />
        <div className="text-xs text-slate-500">
          Unit selection datasource is not available in FE code yet. Enter a UnitId GUID if
          required.
        </div>
      </Modal.Content>

      <Modal.Footer>
        <Modal.Actions
          onCancel={onCancel}
          onOk={onOk}
          cancelText="Cancel"
          okText="Create"
          confirmLoading={confirmLoading}
        />
      </Modal.Footer>
    </Modal>
  );
}

'use client';

import { Select } from 'antd';

import Card from '@/components/ui/card';
import SearchBar from '@/components/ui/searchbar';

import { useAdminUsersContext } from '../context/AdminUsersContext';

export default function AdminUsersFilters() {
  const {
    search,
    setSearch,
    role,
    setRole,
    status,
    setStatus,
    roleOptions,
    statusOptions,
    err,
    setCreateOpen,
    setPageNumber,
  } = useAdminUsersContext();

  return (
    <Card className="min-h-0">
      <Card.Header className="border-b border-slate-100 pb-4">
        <div>
          <Card.Title>Admin users</Card.Title>
          <Card.Description>Manage administrative accounts across the system</Card.Description>
        </div>
        <Card.Action>
          <button
            type="button"
            onClick={() => setCreateOpen(true)}
            className="bg-primary hover:bg-primary-hover flex cursor-pointer items-center gap-2 rounded-full px-5 py-2 text-sm font-medium text-white"
          >
            Create
          </button>
        </Card.Action>
      </Card.Header>

      <Card.Content className="space-y-3 pt-4">
        <SearchBar
          placeholder="Search name/email/code"
          value={search}
          onChange={setSearch}
          showAction={false}
          showFilter
          onFilterClick={() => {}}
        />

        <div className="flex flex-wrap items-center gap-3">
          <div className="w-56">
            <Select
              allowClear
              placeholder="Filter role"
              value={role}
              onChange={(v) => {
                setRole(v);
                setPageNumber(1);
              }}
              options={roleOptions}
              className="w-full"
            />
          </div>

          <div className="w-56">
            <Select
              allowClear
              placeholder="Filter status"
              value={status}
              onChange={(v) => {
                setStatus(v);
                setPageNumber(1);
              }}
              options={statusOptions}
              className="w-full"
            />
          </div>

          {!!err && <span className="text-sm font-medium text-red-600">{String(err)}</span>}
        </div>
      </Card.Content>
    </Card>
  );
}

'use client';

import { Trash2 } from 'lucide-react';
import { useEffect, useState } from 'react';

import { Button } from '@/components/ui/button';
import { Checkbox } from '@/components/ui/checkbox';
import {
  Dialog,
  DialogClose,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { Field } from '@/components/ui/field';
import { UI_TEXT } from '@/lib/UI_Text';
import { useToast } from '@/providers/ToastProvider';
import { useAdminUsersStore } from '@/store/useAdminUsersStore';

import { adminUsersService } from '../adminUsers.service';

export default function AdminUserDeleteModal({ open, userId, label, onToggle }) {
  const toast = useToast();
  const [confirmed, setConfirmed] = useState(false);
  const [busy, setBusy] = useState(false);

  useEffect(() => {
    if (open) {
      setConfirmed(false);
      setBusy(false);
    }
  }, [open]);

  const doDelete = async (e) => {
    e.preventDefault();
    if (!confirmed) {
      toast.error('Please confirm delete.');
      return;
    }
    if (!userId) return;

    setBusy(true);
    try {
      await adminUsersService.delete(userId);
      toast.success('Deleted user');
      useAdminUsersStore.increment();
      onToggle?.(false);
    } catch (err) {
      toast.error(err?.data?.message || err?.message || 'Delete failed');
    } finally {
      setBusy(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onToggle}>
      <DialogContent aria-describedby={undefined} className="sm:max-w-sm">
        <form onSubmit={doDelete}>
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2 text-xl font-bold">
              <Trash2 className="h-6 w-6 text-rose-600" />
              {UI_TEXT.ADMIN_USERS.DELETE}
            </DialogTitle>
            <DialogDescription>This action cannot be undone.</DialogDescription>
          </DialogHeader>

          <div className="mt-4 space-y-3">
            <div className="text-sm text-slate-700">
              Delete <b>{label || '-'}</b>?
            </div>

            <Field orientation="horizontal" className="gap-3">
              <Checkbox checked={confirmed} onCheckedChange={setConfirmed} />
              <div className="space-y-1">
                <span className="text-sm font-semibold">Confirm delete</span>
                <p className="text-xs text-slate-500">User will lose access to the system.</p>
              </div>
            </Field>
          </div>

          <DialogFooter className="mt-4">
            <DialogClose asChild>
              <Button type="button" variant="outline">
                {UI_TEXT.BUTTON.CLOSE}
              </Button>
            </DialogClose>
            <Button type="submit" disabled={busy || !confirmed} variant="destructive">
              {UI_TEXT.BUTTON.DELETE}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

'use client';

import { useEffect, useState } from 'react';

import { Button } from '@/components/ui/button';
import {
  Dialog,
  DialogClose,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { Field, FieldGroup, FieldLabel } from '@/components/ui/field';
import { Textarea } from '@/components/ui/textarea';
import { UI_TEXT } from '@/lib/UI_Text';
import { useToast } from '@/providers/ToastProvider';
import { useAdminUsersStore } from '@/store/useAdminUsersStore';

import { adminUsersService } from '../adminUsers.service';

export default function AdminUserResetPasswordModal({ open, userId, email, onToggle }) {
  const toast = useToast();
  const [busy, setBusy] = useState(false);
  const [reason, setReason] = useState('');

  useEffect(() => {
    if (open) setReason('');
  }, [open]);

  const doReset = async (e) => {
    e.preventDefault();
    if (!userId) return;
    const trimmed = reason.trim();
    if (trimmed.length < 10) {
      toast.error('Reason must be at least 10 characters');
      return;
    }
    if (trimmed.length > 500) {
      toast.error('Reason must be at most 500 characters');
      return;
    }

    setBusy(true);
    try {
      await adminUsersService.resetPassword(userId, trimmed);
      toast.success('Password reset email queued');
      useAdminUsersStore.increment();
      onToggle?.(false);
    } catch (err) {
      toast.error(err?.data?.message || err?.message || 'Reset password failed');
    } finally {
      setBusy(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onToggle}>
      <DialogContent aria-describedby={undefined} className="sm:max-w-sm">
        <form onSubmit={doReset}>
          <DialogHeader>
            <DialogTitle>{UI_TEXT.ADMIN_USERS.RESET_PASSWORD}</DialogTitle>
            <DialogDescription>{UI_TEXT.ADMIN_USERS.ACCOUNT_SECURITY}</DialogDescription>
          </DialogHeader>

          <FieldGroup className="mt-4 gap-4">
            <Field>
              <FieldLabel>Target</FieldLabel>
              <div className="rounded-md border border-slate-100 bg-slate-50 px-3 py-2 text-sm text-slate-700">
                {email || '-'}
              </div>
            </Field>

            <Field>
              <FieldLabel htmlFor="reason">Reason</FieldLabel>
              <Textarea
                id="reason"
                value={reason}
                onChange={(e) => setReason(e.target.value)}
                placeholder="Reason (10..500 chars)"
              />
            </Field>
          </FieldGroup>

          <DialogFooter className="mt-4">
            <DialogClose asChild>
              <Button type="button" variant="outline">
                {UI_TEXT.BUTTON.CLOSE}
              </Button>
            </DialogClose>
            <Button type="submit" disabled={busy}>
              {UI_TEXT.ADMIN_USERS.RESET_PASSWORD}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

'use client';

import { useEffect, useState } from 'react';

import { Button } from '@/components/ui/button';
import { Field, FieldGroup, FieldLabel } from '@/components/ui/field';
import { Input } from '@/components/ui/input';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import {
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
} from '@/components/ui/sheet';
import { USER_ROLE, USER_STATUS, USER_STATUS_LABEL } from '@/constants/admin-users/enums';
import { UI_TEXT } from '@/lib/UI_Text';
import { useToast } from '@/providers/ToastProvider';
import { useAdminUsersStore } from '@/store/useAdminUsersStore';

import { adminUsersService } from '../adminUsers.service';

const initialEditForm = {
  fullName: '',
  phoneNumber: '',
  status: '',
  dateOfBirth: '',
  gender: '',
  avatarUrl: '',
  studentClass: '',
  studentMajor: '',
  studentGpa: '',
};

export default function AdminUserUpdateModal({ open, userId, onToggle }) {
  const toast = useToast();
  const [busy, setBusy] = useState(false);
  const [detail, setDetail] = useState(null);
  const [editForm, setEditForm] = useState(initialEditForm);
  const [errors, setErrors] = useState({});

  useEffect(() => {
    if (!open) return;
    if (!userId) return;

    let alive = true;
    setBusy(true);
    setDetail(null);

    adminUsersService
      .getById(userId)
      .then((res) => {
        if (!alive) return;
        const data = res?.data ?? res;
        setDetail(data);
        setEditForm({
          fullName: data?.fullName || '',
          phoneNumber: data?.phoneNumber || '',
          status: data?.status ? String(data.status) : '',
          dateOfBirth: data?.dateOfBirth ? String(data.dateOfBirth) : '',
          gender: data?.gender ? String(data.gender) : '',
          avatarUrl: data?.avatarUrl || '',
          studentClass: data?.studentClass || '',
          studentMajor: data?.studentMajor || '',
          studentGpa:
            data?.studentGpa !== null && data?.studentGpa !== undefined
              ? String(data.studentGpa)
              : '',
        });
      })
      .catch((e) => {
        toast.error(e?.data?.message || e?.message || 'Failed to load user detail');
        onToggle?.(false);
      })
      .finally(() => {
        if (alive) setBusy(false);
      });

    return () => {
      alive = false;
    };
  }, [open, toast, userId, onToggle]);

  const doUpdate = async (e) => {
    e.preventDefault();
    if (!userId) return;

    const nextErrors = {};
    if (!editForm.fullName.trim()) nextErrors.fullName = 'Full name is required';
    if (editForm.dateOfBirth && !/^\d{4}-\d{2}-\d{2}$/.test(editForm.dateOfBirth.trim())) {
      nextErrors.dateOfBirth = 'Date of birth must be in YYYY-MM-DD format';
    }
    if (editForm.studentGpa !== '' && Number.isNaN(Number(editForm.studentGpa))) {
      nextErrors.studentGpa = 'Student GPA must be a number';
    }
    setErrors(nextErrors);
    if (Object.keys(nextErrors).length) return;

    const payload = {
      fullName: editForm.fullName.trim(),
      phoneNumber: editForm.phoneNumber?.trim() || undefined,
      status: editForm.status ? Number(editForm.status) : undefined,
      dateOfBirth: editForm.dateOfBirth?.trim() || undefined,
      gender: editForm.gender ? Number(editForm.gender) : undefined,
      avatarUrl: editForm.avatarUrl?.trim() || undefined,
      studentClass: editForm.studentClass?.trim() || undefined,
      studentMajor: editForm.studentMajor?.trim() || undefined,
      studentGpa: editForm.studentGpa !== '' ? Number(editForm.studentGpa) : undefined,
    };

    setBusy(true);
    try {
      await adminUsersService.update(userId, payload);
      toast.success('Updated user');
      useAdminUsersStore.increment();
      onToggle?.(false);
    } catch (e2) {
      toast.error(e2?.data?.message || e2?.message || 'Update failed');
    } finally {
      setBusy(false);
    }
  };

  return (
    <Sheet open={open} onOpenChange={onToggle}>
      <SheetContent className="flex flex-col p-4 sm:max-w-[560px]">
        <form onSubmit={doUpdate} className="flex min-h-0 flex-1 flex-col">
          <SheetHeader className="mt-2 text-center">
            <SheetTitle className="text-3xl">{UI_TEXT.ADMIN_USERS.UPDATE_PROFILE}</SheetTitle>
            <SheetDescription>{UI_TEXT.ADMIN_USERS.UPDATE_INFO}</SheetDescription>
          </SheetHeader>

          <FieldGroup className="mt-4 min-h-0 flex-1 gap-4 overflow-y-auto pb-8">
            <Field>
              <FieldLabel htmlFor="fullName">{UI_TEXT.ADMIN_USERS.FULL_NAME_LABEL}</FieldLabel>
              <Input
                id="fullName"
                value={editForm.fullName}
                onChange={(e) => setEditForm((p) => ({ ...p, fullName: e.target.value }))}
                error={errors.fullName}
              />
            </Field>

            <Field>
              <FieldLabel htmlFor="phoneNumber">{UI_TEXT.ADMIN_USERS.PHONE_OPTIONAL}</FieldLabel>
              <Input
                id="phoneNumber"
                value={editForm.phoneNumber}
                onChange={(e) => setEditForm((p) => ({ ...p, phoneNumber: e.target.value }))}
              />
            </Field>

            <div className="grid grid-cols-1 gap-4 md:grid-cols-2">
              <Field>
                <FieldLabel>{UI_TEXT.ADMIN_USERS.STATUS}</FieldLabel>
                <Select
                  value={editForm.status}
                  onValueChange={(v) => setEditForm((p) => ({ ...p, status: v }))}
                >
                  <SelectTrigger>
                    <SelectValue placeholder={UI_TEXT.ADMIN_USERS.STATUS} />
                  </SelectTrigger>
                  <SelectContent position="popper">
                    <SelectItem value="">{UI_TEXT.COMMON.MINUS}</SelectItem>
                    {Object.values(USER_STATUS).map((v) => (
                      <SelectItem key={String(v)} value={String(v)}>
                        {USER_STATUS_LABEL[v] || String(v)}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </Field>

              <Field>
                <FieldLabel>Gender</FieldLabel>
                <Select
                  value={editForm.gender}
                  onValueChange={(v) => setEditForm((p) => ({ ...p, gender: v }))}
                >
                  <SelectTrigger>
                    <SelectValue placeholder={UI_TEXT.ADMIN_USERS.GENDER} />
                  </SelectTrigger>
                  <SelectContent position="popper">
                    <SelectItem value="">{UI_TEXT.COMMON.MINUS}</SelectItem>
                    <SelectItem value="1">{UI_TEXT.ADMIN_USERS.MALE}</SelectItem>
                    <SelectItem value="2">{UI_TEXT.ADMIN_USERS.FEMALE}</SelectItem>
                    <SelectItem value="3">{UI_TEXT.ADMIN_USERS.OTHER}</SelectItem>
                  </SelectContent>
                </Select>
              </Field>
            </div>

            <Field>
              <FieldLabel htmlFor="dateOfBirth">{UI_TEXT.ADMIN_USERS.DOB_LABEL}</FieldLabel>
              <Input
                id="dateOfBirth"
                value={editForm.dateOfBirth}
                onChange={(e) => setEditForm((p) => ({ ...p, dateOfBirth: e.target.value }))}
                error={errors.dateOfBirth}
              />
            </Field>

            <Field>
              <FieldLabel htmlFor="avatarUrl">{UI_TEXT.ADMIN_USERS.AVATAR_LABEL}</FieldLabel>
              <Input
                id="avatarUrl"
                value={editForm.avatarUrl}
                onChange={(e) => setEditForm((p) => ({ ...p, avatarUrl: e.target.value }))}
              />
            </Field>

            {detail?.role === USER_ROLE.STUDENT ? (
              <>
                <Field>
                  <FieldLabel htmlFor="studentClass">{UI_TEXT.ADMIN_USERS.CLASS_LABEL}</FieldLabel>
                  <Input
                    id="studentClass"
                    value={editForm.studentClass}
                    onChange={(e) => setEditForm((p) => ({ ...p, studentClass: e.target.value }))}
                  />
                </Field>
                <Field>
                  <FieldLabel htmlFor="studentMajor">{UI_TEXT.ADMIN_USERS.MAJOR_LABEL}</FieldLabel>
                  <Input
                    id="studentMajor"
                    value={editForm.studentMajor}
                    onChange={(e) => setEditForm((p) => ({ ...p, studentMajor: e.target.value }))}
                  />
                </Field>
                <Field>
                  <FieldLabel htmlFor="studentGpa">{UI_TEXT.ADMIN_USERS.GPA_LABEL}</FieldLabel>
                  <Input
                    id="studentGpa"
                    value={editForm.studentGpa}
                    onChange={(e) => setEditForm((p) => ({ ...p, studentGpa: e.target.value }))}
                    error={errors.studentGpa}
                  />
                </Field>
              </>
            ) : null}
          </FieldGroup>

          <div className="mt-auto border-t border-slate-100 pt-4">
            <div className="flex flex-col-reverse gap-2 sm:flex-row sm:justify-end">
              <Button type="button" variant="outline" onClick={() => onToggle?.(false)}>
                {UI_TEXT.BUTTON.CLOSE}
              </Button>
              <Button type="submit" disabled={busy}>
                {UI_TEXT.BUTTON.SAVE_CHANGES}
              </Button>
            </div>
          </div>
        </form>
      </SheetContent>
    </Sheet>
  );
}

import { Dropdown } from 'antd';
import { ChevronDown } from 'lucide-react';
import React from 'react';

import { BACKLOG_UI } from '@/constants/backlog/uiText';

function FieldLabel({ required, children }) {
  return (
    <div className="text-text mb-2 text-sm font-semibold">
      {children}
      {required ? <span className="text-primary"> *</span> : null}
    </div>
  );
}

export function BacklogItemSelector({
  allEpics,
  selectedEpicId,
  setSelectedEpicId,
  loadingItems,
  filteredItems,
  selectedItemIds,
  toggleSelection,
  toggleAll,
  isAllFilteredSelected,
}) {
  const currentEpic = allEpics.find((e) => e.id === selectedEpicId);

  const menuItems = allEpics.map((epic) => ({
    key: epic.id,
    label: (
      <div className="max-w-[320px] truncate py-1 text-sm font-medium">
        {epic.name || epic.title || 'Unknown Epic'}
      </div>
    ),
    onClick: () => setSelectedEpicId(epic.id),
  }));

  return (
    <div className="flex max-h-[500px] min-h-[400px] w-[60%] flex-col">
      <div className="mb-2 flex items-center justify-between">
        <FieldLabel>
          {BACKLOG_UI.SELECT_ISSUE_SPRINT} ({selectedItemIds.length})
        </FieldLabel>

        <Dropdown
          menu={{
            items: menuItems,
            selectable: true,
            selectedKeys: [selectedEpicId],
          }}
          trigger={['click']}
          placement="bottomRight"
          getPopupContainer={(triggerNode) => triggerNode.parentNode}
        >
          <div className="border-border/60 hover:border-primary/60 flex h-10 w-full max-w-[280px] cursor-pointer items-center justify-between rounded-xl border bg-white px-4 transition-all hover:shadow-sm active:scale-[0.98]">
            <span
              className={`truncate text-sm font-bold ${
                selectedEpicId ? 'text-gray-900' : 'text-gray-400'
              }`}
            >
              {currentEpic ? currentEpic.name || currentEpic.title : BACKLOG_UI.SELECT_AN_EPIC}
            </span>
            <ChevronDown className="ml-2 h-4 w-4 shrink-0 text-gray-400" />
          </div>
        </Dropdown>
      </div>

      <div className="border-border/60 flex-1 overflow-y-auto rounded-xl border bg-white shadow-sm">
        {loadingItems ? (
          <div className="text-muted p-6 text-center text-sm">{BACKLOG_UI.LOADING_LIST}</div>
        ) : !selectedEpicId ? (
          <div className="text-muted p-6 text-center text-sm">{BACKLOG_UI.SELECT_EPIC_PROMPT}</div>
        ) : filteredItems.length === 0 ? (
          <div className="text-muted p-6 text-center text-sm">{BACKLOG_UI.EMPTY_ISSUES}</div>
        ) : (
          <div className="divide-border/20 divide-y">
            {/* Select All Header */}
            <label className="border-border/40 sticky top-0 z-10 flex cursor-pointer items-center border-b bg-white/95 px-4 py-3 backdrop-blur-md transition-colors hover:bg-gray-50/80">
              <input
                type="checkbox"
                className="text-primary focus:ring-primary mr-4 h-4 w-4 cursor-pointer rounded border-gray-300"
                checked={isAllFilteredSelected}
                onChange={toggleAll}
              />
              <span className="text-[14px] font-bold tracking-wide text-gray-800">
                {BACKLOG_UI.SELECT_ALL}
              </span>
            </label>

            {/* Item List */}
            {filteredItems.map((it, idx) => (
              <label
                key={it._id}
                className="group flex cursor-pointer items-start px-4 py-4 transition-colors hover:bg-gray-50/50"
              >
                <input
                  type="checkbox"
                  className="text-primary focus:ring-primary mt-1 mr-4 h-4 w-4 cursor-pointer rounded border-gray-300"
                  checked={selectedItemIds.includes(it._id)}
                  onChange={() => toggleSelection(it._id)}
                />
                <div className="flex min-w-0 flex-1 flex-col gap-2">
                  <div className="flex items-center gap-3">
                    <span className="shrink-0 text-[12px] font-bold tracking-wider text-gray-400 uppercase">
                      {it.key || `ISSUE-${idx + 1}`}
                    </span>
                    <span
                      className="text-text truncate text-[14px] font-semibold transition-colors"
                      dangerouslySetInnerHTML={{
                        __html: it.title || it.name || 'Untitled Issue',
                      }}
                    />
                  </div>
                  <div className="flex items-center gap-2">
                    <span className="inline-flex items-center justify-center truncate rounded border border-purple-200 bg-purple-50 px-2 py-0.5 text-[11px] font-semibold text-purple-600">
                      {it.epicName || BACKLOG_UI.TYPE_EPIC}
                    </span>
                  </div>
                </div>
              </label>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

'use client';

import { useMemo, useState } from 'react';

import { BACKLOG_UI } from '@/constants/backlog/uiText';
import {
  MOVE_INCOMPLETE_ITEMS_OPTION,
  SPRINT_STATUS,
  WORK_ITEM_STATUS,
} from '@/constants/common/enums';

export default function CompleteSprintModal({ open, sprint, sprints, onClose, onSubmit }) {
  const [moveOption, setMoveOption] = useState('backlog'); // Default to Backlog for safety
  const [userSelectedNextSprintId, setUserSelectedNextSprintId] = useState(null);
  const [newSprintName, setNewSprintName] = useState('');

  const sprintItems = sprint?.items || [];
  const undoneItems = sprintItems.filter((it) => {
    const status = it.status?.name || it.status;
    return status !== WORK_ITEM_STATUS.DONE && status !== 'DONE';
  });

  // Filter planned (future) sprints (also accepts null/undefined statuses)
  const futureSprints = useMemo(() => {
    return (sprints || []).filter(
      (s) =>
        s.sprintId !== sprint?.sprintId &&
        (!s.status ||
          s.status === SPRINT_STATUS.PLANNED ||
          (typeof s.status === 'string' && s.status.toUpperCase() === 'PLANNED'))
    );
  }, [sprints, sprint]);

  const selectedNextSprintId = userSelectedNextSprintId ?? futureSprints[0]?.sprintId ?? '';

  if (!open) return null;

  const handleSubmit = () => {
    let option = MOVE_INCOMPLETE_ITEMS_OPTION.TO_BACKLOG;
    let targetId = null;

    if (moveOption === 'next') {
      option = MOVE_INCOMPLETE_ITEMS_OPTION.TO_NEXT_PLANNED_SPRINT;
      targetId = selectedNextSprintId;
    } else if (moveOption === 'new') {
      option = MOVE_INCOMPLETE_ITEMS_OPTION.CREATE_NEW_SPRINT;
    }

    // Backend expects these 3 fields to handle incomplete items
    onSubmit?.({
      incompleteItemsOption: option,
      targetSprintId: targetId,
      newSprintName: moveOption === 'new' ? newSprintName : '',
    });
  };

  return (
    <div className="fixed inset-0 z-9999 flex items-center justify-center bg-black/40 p-4 backdrop-blur-sm">
      <div className="relative flex w-full max-w-[500px] flex-col rounded-3xl bg-white p-8 shadow-2xl">
        <h2 className="mb-2 text-2xl font-bold text-gray-900">
          {BACKLOG_UI.COMPLETE_SPRINT_TITLE} {sprint?.name}
        </h2>
        <p className="mb-6 text-sm font-medium text-gray-500">
          {BACKLOG_UI.INCOMPLETE_ISSUES_PROMPT} ({undoneItems.length})
        </p>

        <div className="mb-8 space-y-4">
          {/* 1. Move to backlog */}
          <label className="flex cursor-pointer items-center gap-3 rounded-xl border border-transparent p-3 transition-colors hover:bg-gray-50">
            <input
              type="radio"
              checked={moveOption === 'backlog'}
              onChange={() => setMoveOption('backlog')}
              className="text-primary focus:ring-primary h-4 w-4"
            />
            <span className="text-sm font-semibold text-gray-700">
              {BACKLOG_UI.OPT_PRODUCT_BACKLOG}
            </span>
          </label>

          {/* 2. Move to next planned sprint */}
          <div className="space-y-2">
            <label className="flex cursor-pointer items-center gap-3 rounded-xl border border-transparent p-3 transition-colors hover:bg-gray-50">
              <input
                type="radio"
                checked={moveOption === 'next'}
                onChange={() => setMoveOption('next')}
                className="text-primary focus:ring-primary h-4 w-4"
              />
              <span className="text-sm font-semibold text-gray-700">
                {BACKLOG_UI.OPT_NEXT_SPRINT}
              </span>
            </label>
            {moveOption === 'next' && (
              <div className="animate-in slide-in-from-left-2 ml-9">
                <select
                  value={selectedNextSprintId}
                  onChange={(e) => setUserSelectedNextSprintId(e.target.value)}
                  className="focus:border-primary h-10 w-full rounded-xl border border-gray-200 px-3 text-sm font-medium transition-all outline-none"
                >
                  {futureSprints.map((s) => (
                    <option key={s.sprintId} value={s.sprintId}>
                      {s.name || s.title}
                    </option>
                  ))}
                  {futureSprints.length === 0 && (
                    <option value="">{BACKLOG_UI.NO_PLANNED_SPRINT}</option>
                  )}
                </select>
              </div>
            )}
          </div>
          {/* 3. Move to a new sprint */}
          <div className="space-y-2">
            <label className="flex cursor-pointer items-center gap-3 rounded-xl border border-transparent p-3 transition-colors hover:bg-gray-50">
              <input
                type="radio"
                checked={moveOption === 'new'}
                onChange={() => setMoveOption('new')}
                className="text-primary focus:ring-primary h-4 w-4"
              />
              <span className="text-sm font-semibold text-gray-700">
                {BACKLOG_UI.OPT_NEW_SPRINT}
              </span>
            </label>
            {moveOption === 'new' && (
              <div className="animate-in slide-in-from-left-2 ml-9">
                <input
                  type="text"
                  placeholder={BACKLOG_UI.PLACEHOLDER_NEW_SPRINT}
                  value={newSprintName}
                  onChange={(e) => setNewSprintName(e.target.value)}
                  className="border-primary/20 bg-primary-50/20 focus:ring-primary/20 h-10 w-full rounded-xl border px-4 text-sm outline-none focus:ring-2"
                  autoFocus
                />
              </div>
            )}
          </div>
        </div>

        <div className="flex justify-end gap-3 border-t border-gray-100 pt-6">
          <button
            onClick={onClose}
            className="h-11 rounded-full px-6 font-bold text-gray-500 hover:bg-gray-100"
          >
            {BACKLOG_UI.CANCEL}
          </button>
          <button
            onClick={handleSubmit}
            disabled={moveOption === 'new' && !newSprintName.trim()}
            className="bg-primary hover:bg-primary-hover h-11 rounded-full px-8 font-bold text-white shadow-lg disabled:opacity-50"
          >
            {BACKLOG_UI.COMPLETE_SPRINT}
          </button>
        </div>
      </div>
    </div>
  );
}

