'use client';

import { useMemo, useState } from 'react';

import DateInput from '@/components/ui/dateinput';
import TiptapEditor from '@/components/ui/tiptapeditor';
import { BACKLOG_UI } from '@/constants/backlog/uiText';

function FieldLabel({ required, children }) {
  return (
    <div className="text-text mb-2 text-sm font-semibold">
      {children}
      {required ? <span className="text-primary"> *</span> : null}
    </div>
  );
}

function TextInput({ value, onChange, placeholder = '' }) {
  return (
    <input
      value={value}
      onChange={(e) => onChange?.(e.target.value)}
      placeholder={placeholder}
      className="border-border focus:border-primary h-11 w-full rounded-2xl border bg-white px-4 text-sm outline-none"
    />
  );
}

export default function UpdateEpicModal({ open, onClose, onSubmit, initialData }) {
  const [epicName, setEpicName] = useState(() => initialData?.title || initialData?.name || '');
  const [desc, setDesc] = useState(() => initialData?.description || '');
  const [endDate, setEndDate] = useState(() => initialData?.endDate || '');

  const canSubmit = useMemo(() => epicName.trim() !== '', [epicName]);

  function handleClose() {
    onClose?.();
  }

  function handleSubmit() {
    if (!canSubmit) return;
    onSubmit?.({
      name: epicName.trim(),
      description: desc,
      endDate,
    });
  }

  if (!open) return null;

  return (
    <div className="fixed inset-0 z-999 flex items-center justify-center p-4 backdrop-blur-sm">
      {/* overlay */}
      <button
        type="button"
        aria-label="overlay"
        onClick={handleClose}
        className="absolute inset-0 bg-black/40 transition-opacity"
