'use client';

import { useState } from 'react';

import { Button } from '@/components/ui/button';
import { Field, FieldGroup, FieldLabel } from '@/components/ui/field';
import { Input } from '@/components/ui/input';
import LogoUploader from '@/components/ui/logouploader';
import { Spinner } from '@/components/ui/spinner';
import { Textarea } from '@/components/ui/textarea';
import { useToast } from '@/providers/ToastProvider';
import { enterpriseService } from '@/services/enterprise.service';
import { useEnterprisesStore } from '@/store/useEnterprisesStore';

export default function EnterprisesForm({ enterprise, onSuccess, onCancel }) {
  const toast = useToast();
  const [loading, setLoading] = useState(false);
  const [errors, setErrors] = useState({});
  const [formError, setFormError] = useState('');
  const [logoUrl, setLogoUrl] = useState(enterprise?.logoUrl || '');
  const [backgroundUrl, setBackgroundUrl] = useState(enterprise?.backgroundUrl || '');
  const isEdit = !!enterprise;

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    const formData = new FormData(e.currentTarget);
    const payload = {
      name: String(formData.get('name') || '').trim(),
      taxCode: String(formData.get('taxCode') || '').trim() || undefined,
      industry: String(formData.get('industry') || '').trim() || undefined,
      description: String(formData.get('description') || '').trim() || undefined,
      address: String(formData.get('address') || '').trim() || undefined,
      website: String(formData.get('website') || '').trim() || undefined,
    };

    const nextErrors = {};
    if (!payload.name) nextErrors.name = 'Enterprise name is required';
    if (payload.website && !/^https?:\/\/.+/i.test(payload.website))
      nextErrors.website = 'Website must start with http:// or https://';
    setErrors(nextErrors);

    if (Object.keys(nextErrors).length) {
      setLoading(false);
      return;
    }

    try {
      setFormError('');
      if (isEdit) {
        await enterpriseService.update(enterprise.enterpriseId || enterprise.id, {
          ...payload,
          logoUrl: logoUrl.trim() || undefined,
          backgroundUrl: backgroundUrl.trim() || undefined,
          enterpriseId: enterprise.enterpriseId || enterprise.id,
        });
        toast.success(`Updated ${payload.name}`);
      } else {
        await enterpriseService.create(payload);
        toast.success(`Created ${payload.name}`);
      }
      useEnterprisesStore.increment();
      onSuccess?.();
    } catch (err) {
      setFormError(err?.data?.message || err?.message || 'Form submission failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="mx-auto flex max-w-2xl flex-col gap-6 pb-2">
      {isEdit && (
        <div className="mb-4 flex items-end justify-center gap-6">
          <div className="flex flex-col items-center gap-2">
            <span className="text-[11px] font-bold tracking-widest text-slate-400 uppercase">
              Brand Logo
            </span>
            <LogoUploader
              value={logoUrl}
              onChange={setLogoUrl}
              size={100}
              label="Logo"
              folder="Enterprises"
            />
          </div>
          <div className="flex flex-col items-center gap-2">
            <span className="text-[11px] font-bold tracking-widest text-slate-400 uppercase">
              Cover Image
            </span>
            <LogoUploader
              value={backgroundUrl}
              onChange={setBackgroundUrl}
              size={180}
              label="Background"
              folder="Enterprises/Backgrounds"
            />
          </div>
        </div>
      )}

      <FieldGroup className="grid grid-cols-1 gap-5 md:grid-cols-2">
        <Field className="md:col-span-2">
          <FieldLabel htmlFor="name">Enterprise Name</FieldLabel>
          <Input
            id="name"
            name="name"
            defaultValue={enterprise?.name}
            required
            placeholder="Official commercial name"
            className="h-12 rounded-xl border-slate-200"
            error={errors.name}
          />
        </Field>

        <Field>
          <FieldLabel htmlFor="taxCode">Tax Identification Number</FieldLabel>
          <Input
            id="taxCode"
            name="taxCode"
            defaultValue={enterprise?.taxCode}
            placeholder="Tax Code"
            className="h-11 rounded-xl border-slate-200"
          />
        </Field>

        <Field>
          <FieldLabel htmlFor="industry">Industry Section</FieldLabel>
          <Input
            id="industry"
            name="industry"
            defaultValue={enterprise?.industry}
            placeholder="E.g., Software Development"
            className="h-11 rounded-xl border-slate-200"
          />
        </Field>

        <Field className="md:col-span-2">
          <FieldLabel htmlFor="description">Company Description</FieldLabel>
          <Textarea
            id="description"
            name="description"
            defaultValue={enterprise?.description}
            placeholder="Brief company overview..."
            className="min-h-[100px] resize-none rounded-xl border-slate-200"
          />
        </Field>

        <Field className="md:col-span-2">
          <FieldLabel htmlFor="address">Headquarters Address</FieldLabel>
          <Input
            id="address"
            name="address"
            defaultValue={enterprise?.address}
            placeholder="Full registered address"
            className="h-11 rounded-xl border-slate-200"
          />
        </Field>

        <Field className="md:col-span-2">
          <FieldLabel htmlFor="website">Corporate Website</FieldLabel>
          <Input
            id="website"
            name="website"
            defaultValue={enterprise?.website}
            placeholder="https://example.com"
            className="text-primary h-11 rounded-xl border-slate-200"
            error={errors.website}
          />
        </Field>
      </FieldGroup>

      {formError && (
        <div className="animate-in slide-in-from-top-1 rounded-xl border border-rose-100 bg-rose-50 p-4 text-center text-sm font-semibold text-rose-600">
          {formError}
        </div>
      )}

      <div className="mt-2 flex justify-end gap-3 border-t border-slate-100 pt-6">
        <Button
          type="button"
          variant="ghost"
          className="h-11 rounded-full bg-slate-50 px-8 font-bold text-slate-500 hover:bg-slate-100"
          onClick={() => onCancel?.()}
        >
          Cancel
        </Button>
        <Button
          type="submit"
          disabled={loading}
          className="bg-primary hover:bg-primary/90 shadow-primary/20 h-11 min-w-[160px] rounded-full px-8 font-bold text-white shadow-lg transition-all"
        >
          {loading ? (
            <Spinner className="mr-2" />
          ) : isEdit ? (
            'Save Changes'
          ) : (
            'Initialize Enterprise'
          )}
        </Button>
      </div>
    </form>
  );
}

'use client';

import { useState } from 'react';

import PageLayout from '@/components/ui/pagelayout';

import EnterprisesDialog from './EnterprisesDialog';
import EnterprisesTable from './EnterprisesTable';
import { useEnterprises } from './useEnterprises';

export default function EnterprisesPage() {
  const {
    enterprises,
    loading,
    total,
    pageNumber,
    setPageNumber,
    pageSize,
    setPageSize,
    search,
    setSearch,
    refresh,
    error,
  } = useEnterprises();
  const [isDialogOpen, setIsDialogOpen] = useState(false);

  return (
    <PageLayout>
      <PageLayout.Header
        title="Strategic Corporate Partners"
        description="Oversee corporate registration, tax compliance, and commercial sector alignment within the ecosystem."
      />

      <PageLayout.Card>
        <PageLayout.Toolbar
          searchProps={{
            placeholder: 'Search by enterprise name, code, or tax ID...',
            value: search,
            onChange: (e) => setSearch(e.target.value),
          }}
          actionProps={{
            label: 'Add Enterprise',
            onClick: () => setIsDialogOpen(true),
          }}
        />

        <PageLayout.Content>
          {error ? (
            <div className="animate-in zoom-in-95 flex h-64 flex-col items-center justify-center rounded-3xl border border-rose-100 bg-rose-50 p-8 text-rose-600 duration-300">
              <p className="mb-2 font-bold">Communication Error</p>
              <p className="text-sm opacity-80">{error}</p>
              <button
                onClick={refresh}
                className="mt-4 rounded-full bg-rose-600 px-6 py-2 text-sm font-semibold text-white transition-all hover:bg-rose-700 active:scale-95"
              >
                Try Again
              </button>
            </div>
          ) : (
            <EnterprisesTable enterprises={enterprises} loading={loading} />
          )}
        </PageLayout.Content>

        {total > 0 && (
          <PageLayout.Pagination
            total={total}
            page={pageNumber}
            pageSize={pageSize}
            onPageChange={setPageNumber}
            onPageSizeChange={setPageSize}
          />
        )}
      </PageLayout.Card>

      <EnterprisesDialog open={isDialogOpen} onOpenChange={setIsDialogOpen} controlled />
    </PageLayout>
  );
}

'use client';

import { MessageOutlined, StarFilled } from '@ant-design/icons';
import { Card, Descriptions, Divider, Drawer, Empty, Progress, Space, Typography } from 'antd';
import dayjs from 'dayjs';

import { EVALUATION_UI } from '@/constants/evaluation/evaluation';

const { Text, Paragraph } = Typography;

export default function ScoreDetailDrawer({ visible, cycle, onClose, evaluationDetail }) {
  if (!cycle) return null;

  return (
    <Drawer
      title={<Text className="text-text text-lg font-bold">{cycle.name}</Text>}
      placement="right"
      size="large"
      onClose={onClose}
      open={visible}
    >
      {!evaluationDetail ? (
        <Empty description={EVALUATION_UI.LABELS.SCORECARD_NOT_READY} />
      ) : (
        <Space orientation="vertical" size="large" style={{ width: '100%' }}>
          <Card className="border-border/60 shadow-sm">
            <Descriptions column={1} size="small">
              <Descriptions.Item label={EVALUATION_UI.LABELS.EVALUATOR}>
                <Text strong className="text-text">
                  {evaluationDetail.evaluatorName}
                </Text>
              </Descriptions.Item>

              <Descriptions.Item label={EVALUATION_UI.LABELS.TIME}>
                <Text className="text-muted-foreground text-xs">
                  {dayjs(evaluationDetail.gradedAt).format('DD/MM/YYYY HH:mm')}
                </Text>
              </Descriptions.Item>

              <Descriptions.Item label={EVALUATION_UI.LABELS.TOTAL_SCORE}>
                <div className="flex items-baseline gap-1">
                  <span className="text-primary text-3xl font-black">
                    {Number(evaluationDetail.totalScore).toFixed(1)}
                  </span>
                  <Text type="secondary" className="text-sm">
                    / 10
                  </Text>
                </div>
              </Descriptions.Item>
            </Descriptions>
          </Card>

          <Card
            className="border-border/60 shadow-sm"
            title={
              <Space className="text-primary">
                <MessageOutlined />
                {EVALUATION_UI.LABELS.MENTOR_COMMENTS}
              </Space>
            }
          >
            <Paragraph italic className="text-text/80 mt-2">
              {evaluationDetail.generalComment || EVALUATION_UI.LABELS.NO_COMMENTS}
            </Paragraph>
          </Card>

          <Card
            className="border-border/60 shadow-sm"
            title={
              <Space className="text-primary">
                <StarFilled />
                {EVALUATION_UI.LABELS.CRITERIA_SCORES}
              </Space>
            }
          >
            <div className="flex flex-col gap-4">
              {evaluationDetail.criteriaScores?.map((criteria, index) => {
                const percent = (criteria.score / criteria.maxScore) * 100;

                return (
                  <div key={index} className="flex flex-col gap-2">
                    <div className="flex items-center justify-between">
                      <Text strong>{criteria.criteriaName}</Text>
                      <Text>
                        {criteria.score} / {criteria.maxScore}
                      </Text>
                    </div>

                    <Progress percent={percent} showInfo={false} />

                    <Text type="secondary" italic>
                      {criteria.comment || EVALUATION_UI.LABELS.NO_DETAILED_COMMENTS}
                    </Text>

                    {index < evaluationDetail.criteriaScores.length - 1 && (
                      <Divider style={{ margin: '8px 0' }} />
                    )}
                  </div>
                );
              })}
            </div>
          </Card>
        </Space>
      )}
    </Drawer>
  );
}

'use client';

import { ClockCircleFilled, EyeOutlined, LockOutlined, TeamOutlined } from '@ant-design/icons';
import { Button, Modal, Space, Tag, Tooltip, Typography } from 'antd';

import AppTable from '@/components/ui/apptable';
import { EVALUATION_UI } from '@/constants/evaluation/evaluation';

const { Text, Title } = Typography;

const getEvalStatusText = (evalStatus) => {
  const status = typeof evalStatus === 'string' ? evalStatus.toUpperCase() : evalStatus;

  switch (status) {
    case 1:
    case 'PENDING':
      return { label: EVALUATION_UI.STATUS.PENDING, color: 'default' };
    case 2:
    case 'DRAFT':
      return { label: EVALUATION_UI.STATUS.DRAFT, color: 'warning' };
    case 3:
    case 'SUBMITTED':
      return { label: EVALUATION_UI.STATUS.SUBMITTED, color: 'processing' };
    case 4:
    case 'PUBLISHED':
      return { label: EVALUATION_UI.STATUS.PUBLISHED, color: 'success' };
    default:
      return { label: evalStatus || EVALUATION_UI.STATUS.UNKNOWN, color: 'default' };
  }
};

export default function TeamEvaluationsModal({
  visible,
  cycle,
  onClose,
  onViewDetails,
  teamData,
  myStudentId,
}) {
  if (!cycle) return null;

  const columns = [
    {
      title: EVALUATION_UI.TABLE_COLUMNS.FULL_NAME,
      dataIndex: 'fullName',
      render: (text, record) => (
        <Text strong type={record.studentId === myStudentId ? 'danger' : undefined}>
          {text}
        </Text>
      ),
    },
    {
      title: EVALUATION_UI.TABLE_COLUMNS.STUDENT_CODE,
      dataIndex: 'studentCode',
      render: (text) => (
        <Text type="secondary" code>
          {text}
        </Text>
      ),
    },
    {
      title: EVALUATION_UI.TABLE_COLUMNS.STATUS,
      dataIndex: 'status',
      align: 'center',
      render: (status) => {
        const conf = getEvalStatusText(status);
        return <Tag color={conf.color}>{conf.label}</Tag>;
      },
    },
    {
      title: EVALUATION_UI.TABLE_COLUMNS.SCORE,
      dataIndex: 'totalScore',
      align: 'center',
      render: (score, record) => {
        const status = record.status;
        const isPublished =
          status === 4 || (typeof status === 'string' && status.toUpperCase() === 'PUBLISHED');

        if (!isPublished) {
          return <Text type="secondary">--</Text>;
        }

        if (record.studentId !== myStudentId) {
          return (
            <Tooltip title={EVALUATION_UI.LABELS.CONFIDENTIAL}>
              <Tag icon={<LockOutlined />}>***</Tag>
            </Tooltip>
          );
        }

        return <Tag color="error">{Number(score).toFixed(1)}</Tag>;
      },
    },
    {
      title: EVALUATION_UI.TABLE_COLUMNS.ACTIONS,
      align: 'right',
      render: (_, record) => {
        if (record.studentId !== myStudentId) return null;

        const status = record.status;
        const isPublished =
          status === 4 || (typeof status === 'string' && status.toUpperCase() === 'PUBLISHED');

        if (!isPublished) {
          return (
            <Tooltip title={EVALUATION_UI.LABELS.NOT_PUBLISHED}>
              <Button type="text" disabled icon={<ClockCircleFilled />}>
                {EVALUATION_UI.LABELS.AWAITING_RESULTS}
              </Button>
            </Tooltip>
          );
        }

        return (
          <Button
            type="primary"
            size="small"
            icon={<EyeOutlined />}
            onClick={() => onViewDetails(cycle)}
            className="bg-primary/95 hover:!bg-primary border-none shadow-sm transition-all"
          >
            {EVALUATION_UI.LABELS.VIEW_REPORT}
          </Button>
        );
      },
    },
  ];

  return (
    <Modal
      title={
        <Space>
          <TeamOutlined className="text-primary" />
          <Title level={4} style={{ margin: 0 }}>
            {EVALUATION_UI.MODAL_TEAM_TITLE}
          </Title>
        </Space>
      }
      open={visible}
      onCancel={onClose}
      footer={null}
      width={850}
      centered
    >
      <Space orientation="vertical" size="large" style={{ width: '100%' }}>
        <AppTable columns={columns} data={teamData} pagination={false} rowKey="studentId" />
      </Space>
    </Modal>
  );
}

import {
  BookOutlined,
  EditOutlined,
  IdcardOutlined,
  InfoCircleOutlined,
  MailOutlined,
  PhoneOutlined,
  PlusCircleOutlined,
  SearchOutlined,
  SettingOutlined,
  StarOutlined,
  UserOutlined,
} from '@ant-design/icons';
import { Col, Empty, Form, Input, Row, Select, Tabs } from 'antd';
import React, { memo, useEffect, useState } from 'react';

import CompoundModal from '@/components/ui/CompoundModal';
import { INTERNSHIP_MANAGEMENT_UI } from '@/constants/internship-management/internship-management';

const StudentFormBody = memo(function StudentFormBody({
  initialValues,
  onSave,
  onClose,
  loading,
  viewOnly,
}) {
  const [form] = Form.useForm();
  const [activeTab, setActiveTab] = useState('1');
  const { STUDENT_ENROLLMENT } = INTERNSHIP_MANAGEMENT_UI.UNI_ADMIN;
  const { MODALS, MAJOR_OPTIONS, STATUS_OPTIONS } = STUDENT_ENROLLMENT;
  const { ADD_EDIT } = MODALS;

  useEffect(() => {
    if (initialValues) {
      form.setFieldsValue({
        fullName: initialValues.name,
        studentCode: initialValues.id,
        email: initialValues.email,
        major: initialValues.major,
        phone: initialValues.phone,
        status: initialValues.status,
      });
    } else {
      form.resetFields();
    }
  }, [initialValues, form]);

  const handleSubmit = async () => {
    try {
      const values = await form.validateFields();
      onSave?.(values);
    } catch (error) {
      if (error.errorFields.length > 0) {
        const firstErrorField = error.errorFields[0].name[0];
        if (['fullName', 'studentCode', 'email', 'major'].includes(firstErrorField)) {
          setActiveTab('1');
        } else {
          setActiveTab('2');
        }
      }
    }
  };

  const title = viewOnly
    ? ADD_EDIT.TITLE_VIEW
    : initialValues
      ? ADD_EDIT.TITLE_EDIT
      : ADD_EDIT.TITLE_ADD;

  const subtitle = viewOnly
    ? ADD_EDIT.SUBTITLE_VIEW
    : initialValues
      ? ADD_EDIT.SUBTITLE_EDIT
      : ADD_EDIT.SUBTITLE_ADD;

  const renderPersonalTab = () => (
    <div className="animate-in fade-in slide-in-from-bottom-2 min-h-[300px] duration-300">
      <Row gutter={16}>
        <Col span={12}>
          <Form.Item
            label={
              <span className="mb-1 block text-[10px] font-bold tracking-wider text-zinc-600 uppercase">
                {ADD_EDIT.NAME_LABEL}
              </span>
            }
            name="fullName"
            rules={[{ required: true, message: ADD_EDIT.NAME_REQUIRED }]}
          >
            <Input
              prefix={<UserOutlined className="text-muted ml-0.5" />}
              placeholder={ADD_EDIT.NAME_PLACEHOLDER}
              className="h-10 rounded-lg"
            />
          </Form.Item>
        </Col>
        <Col span={12}>
          <Form.Item
            label={
              <span className="mb-1 block text-[10px] font-bold tracking-wider text-zinc-600 uppercase">
                {ADD_EDIT.ID_LABEL}
              </span>
            }
            name="studentCode"
            rules={[{ required: true, message: ADD_EDIT.ID_REQUIRED }]}
          >
            <Input
              prefix={<IdcardOutlined className="text-muted ml-0.5" />}
              placeholder={ADD_EDIT.ID_PLACEHOLDER}
              className="h-10 rounded-lg"
            />
          </Form.Item>
        </Col>
      </Row>

      <Form.Item
        label={
          <span className="mb-1 block text-[10px] font-bold tracking-wider text-zinc-600 uppercase">
            {ADD_EDIT.EMAIL_LABEL}
          </span>
        }
        name="email"
        rules={[
          { required: true, message: ADD_EDIT.EMAIL_REQUIRED },
          { type: 'email', message: ADD_EDIT.EMAIL_INVALID },
        ]}
      >
        <Input
          prefix={<MailOutlined className="text-muted ml-0.5" />}
          placeholder={ADD_EDIT.EMAIL_PLACEHOLDER}
          className="h-10 rounded-lg"
        />
      </Form.Item>

      <Row gutter={16}>
        <Col span={12}>
          <Form.Item
            label={
              <span className="mb-1 block text-[10px] font-bold tracking-wider text-zinc-600 uppercase">
                {ADD_EDIT.MAJOR_LABEL}
              </span>
            }
            name="major"
            rules={[{ required: true, message: ADD_EDIT.MAJOR_REQUIRED }]}
          >
            <Select
              placeholder={ADD_EDIT.MAJOR_PLACEHOLDER}
              className="h-10 w-full rounded-lg"
              options={MAJOR_OPTIONS}
              suffixIcon={<BookOutlined />}
            />
          </Form.Item>
        </Col>
        <Col span={12}>
          <Form.Item
            label={
              <span className="mb-1 block text-[10px] font-bold tracking-wider text-zinc-600 uppercase">
                {ADD_EDIT.PHONE_LABEL}
              </span>
            }
            name="phone"
          >
            <Input
              prefix={<PhoneOutlined className="text-muted ml-0.5" />}
              placeholder={ADD_EDIT.PHONE_PLACEHOLDER}
              className="h-10 rounded-lg"
            />
          </Form.Item>
        </Col>
      </Row>
    </div>
  );

  const renderPlacementTab = () => (
    <div className="animate-in fade-in slide-in-from-bottom-2 min-h-[300px] space-y-4 duration-300">
      <Form.Item
        label={
          <span className="mb-1 block text-[10px] font-bold tracking-wider text-zinc-600 uppercase">
            {ADD_EDIT.STATUS_LABEL}
          </span>
        }
        name="status"
      >
        <Select className="h-10 w-full rounded-lg" options={STATUS_OPTIONS} />
      </Form.Item>

      <Form.Item
        label={
          <span className="mb-1 block text-[10px] font-bold tracking-wider text-zinc-600 uppercase">
            {ADD_EDIT.ENTERPRISE_LABEL}
          </span>
        }
      >
        <Input
          disabled
          prefix={<SearchOutlined className="text-muted ml-0.5" />}
          placeholder={ADD_EDIT.ENTERPRISE_PLACEHOLDER}
          className="h-10 rounded-lg"
        />
      </Form.Item>

      {initialValues?.status && (
        <div className="bg-muted/5 border-border mt-6 rounded-xl border p-4">
          <div className="mb-2 flex items-center gap-2">
            <SettingOutlined className="text-primary" />
            <span className="text-muted text-[10px] font-black tracking-wider uppercase">
              {ADD_EDIT.SECTION_PLACEMENT}
            </span>
          </div>
          <p className="text-muted text-xs leading-relaxed">
            This student is currently in the <strong>{initialValues?.status}</strong> phase.
            Business details and evaluations will be updated as the internship progresses.
          </p>
        </div>
      )}
    </div>
  );

  const renderFeedbackTab = () => (
    <div className="animate-in fade-in slide-in-from-bottom-2 border-border/50 bg-bg flex min-h-[300px] flex-col items-center justify-center rounded-2xl border-2 border-dashed p-8 duration-300">
      <Empty
        image={Empty.PRESENTED_IMAGE_SIMPLE}
        description={
          <div className="flex flex-col gap-1">
            <span className="text-text/40 text-sm font-bold">{ADD_EDIT.FEEDBACK_EMPTY.TITLE}</span>
            <span className="text-muted text-[10px] font-medium uppercase">
              {ADD_EDIT.FEEDBACK_EMPTY.SUBTITLE}
            </span>
          </div>
        }
      />
    </div>
  );

  const tabItems = [
    {
      key: '1',
      label: (
        <span className="flex items-center gap-2 px-1">
          <InfoCircleOutlined /> {ADD_EDIT.TABS.GENERAL}
        </span>
      ),
      children: renderPersonalTab(),
    },
    {
      key: '2',
      label: (
        <span className="flex items-center gap-2 px-1">
          <SettingOutlined /> {ADD_EDIT.TABS.PLACEMENT}
        </span>
      ),
      children: renderPlacementTab(),
    },
    {
      key: '3',
      label: (
        <span className="flex items-center gap-2 px-1">
          <StarOutlined /> {ADD_EDIT.TABS.FEEDBACK}
        </span>
      ),
      children: renderFeedbackTab(),
    },
  ];

  return (
    <>
      <CompoundModal.Header title={title} subtitle={subtitle} />
      <CompoundModal.Content className="!pb-2">
        <Form
          form={form}
          layout="vertical"
          className="space-y-4"
          disabled={loading || viewOnly}
          requiredMark={!viewOnly}
        >
          <Tabs
            activeKey={activeTab}
            onChange={setActiveTab}
            items={tabItems}
            className="student-enrollment-tabs"
          />
        </Form>
      </CompoundModal.Content>

      {!viewOnly ? (
        <CompoundModal.Footer
          onCancel={onClose}
          onConfirm={handleSubmit}
          loading={loading}
          cancelText={ADD_EDIT.CANCEL}
          confirmText={initialValues ? ADD_EDIT.SUBMIT_EDIT : ADD_EDIT.SUBMIT_ADD}
          confirmIcon={initialValues ? <EditOutlined /> : <PlusCircleOutlined />}
        />
      ) : (
        <CompoundModal.Footer onCancel={onClose} confirmText={ADD_EDIT.CLOSE} onConfirm={onClose} />
      )}
    </>
  );
});

const StudentFormModal = memo(function StudentFormModal({ visible, onClose, ...props }) {
  return (
    <CompoundModal open={visible} onCancel={onClose} width={520} destroyOnClose>
      {visible && <StudentFormBody onClose={onClose} {...props} />}
    </CompoundModal>
  );
});

export default StudentFormModal;

import { EditOutlined, TeamOutlined } from '@ant-design/icons';
import { Form, Input, Select } from 'antd';
import React, { memo, useEffect } from 'react';

import CompoundModal from '@/components/ui/CompoundModal';
import { INTERNSHIP_MANAGEMENT_UI } from '@/constants/internship-management/internship-management';

export const CreateGroupModal = memo(({ open, onCancel, onFinish }) => {
  const [form] = Form.useForm();
  const { CREATE } = INTERNSHIP_MANAGEMENT_UI.GROUP_MANAGEMENT.MODALS;

  useEffect(() => {
    if (open) form.resetFields();
  }, [open, form]);

  const handleCancel = () => {
    onCancel();
  };

  const handleFinish = (values) => {
    onFinish(values);
    form.resetFields();
  };

  return (
    <CompoundModal open={open} onCancel={handleCancel} width={560} destroyOnHidden>
      <CompoundModal.Header
        icon={<TeamOutlined />}
        title={CREATE.TITLE}
        subtitle={CREATE.SUBTITLE}
      />

      <Form
        form={form}
        layout="vertical"
        onFinish={handleFinish}
        className="p-6 pt-8"
