import { DeleteOutlined, LoadingOutlined, PlusOutlined } from '@ant-design/icons';
import { Upload } from 'antd';
import { useState } from 'react';

import { cn } from '@/lib/cn';
import { useToast } from '@/providers/ToastProvider';
import { mediaService } from '@/services/media.service';

export default function LogoUploader({
  value,
  onChange,
  size = 120,
  label = 'Logo',
  folder = 'General',
}) {
  const [loading, setLoading] = useState(false);
  const toast = useToast();

  const beforeUpload = async (file) => {
    const isImage = ['image/jpeg', 'image/png', 'image/webp', 'image/svg+xml'].includes(file.type);
    if (!isImage) {
      toast.error('Supported formats: JPG, PNG, WEBP, SVG');
      return false;
    }

    const isLt5M = file.size / 1024 / 1024 < 5;
    if (!isLt5M) {
      toast.error('Image must be less than 5MB');
      return false;
    }

    setLoading(true);
    try {
      const response = await mediaService.uploadImage(file, folder);
      if (response.success) {
        onChange?.(response.data); // URL returned from server
        toast.success(`Upload ${label} successfully`);
      } else {
        toast.error(response.message || 'Upload failed');
      }
    } catch (error) {
      toast.error(error.message || 'Server connection error');
    } finally {
      setLoading(false);
    }

    return false; // Prevent Ant Design default upload
  };

  const handleRemove = (e) => {
    e.stopPropagation();
    onChange?.('');
  };

  return (
    <div className="flex flex-col gap-2">
      <Upload showUploadList={false} beforeUpload={beforeUpload}>
        <div
          className={cn(
            'group hover:border-primary/50 relative flex cursor-pointer items-center justify-center overflow-hidden rounded-2xl border-2 border-dashed border-slate-200 bg-slate-50 transition-all hover:bg-slate-100',
            value && 'border-solid border-slate-100 bg-white shadow-sm'
          )}
          style={{ width: size, height: size }}
        >
          {loading ? (
            <div className="flex flex-col items-center gap-2 text-slate-400">
              <LoadingOutlined className="text-2xl" />
              <span className="text-[10px] font-bold tracking-widest uppercase">Loading</span>
            </div>
          ) : value ? (
            <>
              <img
                src={value}
                alt={label}
                className="h-full w-full object-contain p-3"
                draggable={false}
              />
              <div className="absolute inset-0 flex items-center justify-center bg-black/40 opacity-0 transition-opacity group-hover:opacity-100">
                <div className="flex gap-2">
                  <div className="flex h-8 w-8 items-center justify-center rounded-full bg-white text-slate-900 shadow-lg transition-transform active:scale-90">
                    <PlusOutlined />
                  </div>
                  <button
                    onClick={handleRemove}
                    className="flex h-8 w-8 items-center justify-center rounded-full bg-rose-500 text-white shadow-lg transition-transform hover:bg-rose-600 active:scale-90"
                  >
                    <DeleteOutlined />
                  </button>
                </div>
              </div>
            </>
          ) : (
            <div className="flex flex-col items-center gap-2 text-slate-400">
              <div className="flex h-10 w-10 items-center justify-center rounded-xl border border-slate-100 bg-white shadow-sm">
                <PlusOutlined className="text-lg" />
              </div>
              <span className="text-[10px] font-bold tracking-widest uppercase">
                Upload {label}
              </span>
            </div>
          )}
        </div>
      </Upload>
    </div>
  );
}

'use client';

import { useEffect, useRef, useState } from 'react';

export default function MoreMenuButton({
  items = [{ label: 'X├│a', value: 'delete', tone: 'danger' }],
  onSelect,
  align = 'right',
}) {
  const [open, setOpen] = useState(false);
  const rootRef = useRef(null);

  useEffect(() => {
    function onDocMouseDown(e) {
      if (!rootRef.current) return;
      if (!rootRef.current.contains(e.target)) setOpen(false);
    }

    function onKeyDown(e) {
      if (e.key === 'Escape') setOpen(false);
    }

    document.addEventListener('mousedown', onDocMouseDown);
    document.addEventListener('keydown', onKeyDown);
    return () => {
      document.removeEventListener('mousedown', onDocMouseDown);
      document.removeEventListener('keydown', onKeyDown);
    };
  }, []);

  function handleSelect(item) {
    setOpen(false);
    onSelect?.(item);
  }

  return (
    <div ref={rootRef} className="relative inline-flex">
      {/* Icon-only button (default) */}
      <button
        type="button"
        onClick={() => setOpen((v) => !v)}
        className={[
          'group',
          'h-8 w-8 rounded-full',
          'inline-flex items-center justify-center',

          // default (idle)
          'text-[var(--color-muted)]',

          // hover / active
          'hover:text-[var(--primary-600)]',
          'hover:bg-[var(--primary-50)]',
          open ? 'bg-[var(--primary-50)] text-[var(--primary-600)]' : '',

          // focus
          'focus:outline-none',
        ].join(' ')}
        title="More"
        aria-haspopup="menu"
        aria-expanded={open}
      >
        <span className="text-xl leading-none">Γï«</span>
      </button>

      {/* Popover */}
      {open ? (
        <div
          role="menu"
          className={[
            'absolute top-10 z-50 min-w-[120px]',
            align === 'left' ? 'left-0' : 'right-0',
            'rounded-2xl border border-[var(--color-border)]',
            'bg-[var(--color-surface)] shadow-xl',
            'p-1',
          ].join(' ')}
        >
          {items.map((it) => (
            <button
              key={it.value}
              type="button"
              role="menuitem"
              onClick={() => handleSelect(it)}
              className={[
                'flex w-full items-center gap-3',
                'rounded-xl px-3 py-2',
                'text-sm font-semibold',
                'hover:bg-[var(--primary-50)]',
                it.tone === 'danger' ? 'text-[var(--primary-600)]' : 'text-[var(--color-text)]',
              ].join(' ')}
            >
              <TrashIcon />
              <span>{it.label}</span>
            </button>
          ))}
        </div>
      ) : null}
    </div>
  );
}

function TrashIcon() {
  return (
    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" aria-hidden="true">
      <path
        d="M9 3h6m-8 4h10m-9 0 1 14h6l1-14"
        stroke="currentColor"
        strokeWidth="2"
        strokeLinecap="round"
      />
      <path d="M10 11v6M14 11v6" stroke="currentColor" strokeWidth="2" strokeLinecap="round" />
    </svg>
  );
}

'use client';

import { Fragment } from 'react';

export default function Pagination({
  total = 0,
  page = 1,
  pageSize = 10,
  totalPages,
  onPageChange,
  onPageSizeChange,
}) {
  const calculatedTotalPages =
    totalPages !== undefined ? totalPages : Math.max(0, Math.ceil(total / pageSize));
  const pages = getVisiblePages(page, calculatedTotalPages);

  return (
    <div className="flex items-center justify-between text-sm text-slate-600">
      {/* LEFT */}
      <span>
        Total records: <b className="text-slate-800">{total}</b>
      </span>

      {/* RIGHT */}
      <div className="flex items-center gap-2">
        {/* PREV */}
        <button
          disabled={page <= 1}
          onClick={() => onPageChange(page - 1)}
          className="h-9 w-9 rounded-full border text-slate-500 hover:bg-slate-100 disabled:opacity-40"
        >
          ΓÇ╣
        </button>

        {/* PAGE LIST */}
        {pages.map((p, index) => {
          const prev = pages[index - 1];
          const showDots = prev && p - prev > 1;

          return (
            <Fragment key={`${p}-${index}`}>
              {showDots && <span className="px-1 text-slate-400">ΓÇª</span>}

              <button
                onClick={() => onPageChange(p)}
                className={`h-9 w-9 rounded-full text-sm ${
                  page === p ? 'bg-red-500 text-white' : 'border text-slate-600 hover:bg-slate-100'
                }`}
              >
                {p}
              </button>
            </Fragment>
          );
        })}

        {/* NEXT */}
        <button
          disabled={page >= calculatedTotalPages}
          onClick={() => onPageChange(page + 1)}
          className="h-9 w-9 rounded-full border text-slate-500 hover:bg-slate-100 disabled:opacity-40"
        >
          ΓÇ║
        </button>

        <select
          value={pageSize}
          onChange={(e) => onPageSizeChange?.(Number(e.target.value))}
          className="ml-3 rounded-full border px-3 py-1 text-sm"
        >
          <option value={5}>5/page</option>
          <option value={10}>10/page</option>
          <option value={20}>20/page</option>
          <option value={50}>50/page</option>
        </select>
      </div>
    </div>
  );
}

function getVisiblePages(page, totalPages) {
  if (totalPages <= 0) return [];

  const pages = new Set();

  pages.add(1);
  if (totalPages > 1) {
    pages.add(totalPages);
  }

  for (let i = page - 2; i <= page + 2; i++) {
    if (i > 1 && i < totalPages) {
      pages.add(i);
    }
  }

  return Array.from(pages).sort((a, b) => a - b);
}

'use client';

import { FilterOutlined, PlusCircleOutlined, SearchOutlined } from '@ant-design/icons';

export default function SearchBar({
